function mergeSort(arr):
  if len(arr) <= 1: return arr
  mid = len(arr) / 2
  left = mergeSort(arr[:mid])
  right = mergeSort(arr[mid:])
  return merge(left, right)

function merge(L, R):
  result = []
  while L and R:
    if L[0] <= R[0]: result.append(L.pop(0))
    else: result.append(R.pop(0))
  return result + L + R

function quickSort(arr, lo, hi):
  if lo < hi:
    p = partition(arr, lo, hi)
    quickSort(arr, lo, p - 1)
    quickSort(arr, p + 1, hi)

function partition(arr, lo, hi):
  pivot = arr[hi]
  i = lo - 1
  for j = lo to hi - 1:
    if arr[j] < pivot:
      i++; swap(arr[i], arr[j])
  swap(arr[i+1], arr[hi])
  return i + 1

function DFS(graph, start):
  visited = set()
  stack = [start]
  while stack:
    node = stack.pop()
    if node not in visited:
      visited.add(node)
      process(node)
      for neighbor in graph[node]:
        if neighbor not in visited:
          stack.push(neighbor)

function BFS(graph, start):
  visited = set([start])
  queue = [start]
  while queue:
    node = queue.dequeue()
    process(node)
    for neighbor in graph[node]:
      if neighbor not in visited:
        visited.add(neighbor)
        queue.enqueue(neighbor)

function dijkstra(graph, source):
  dist = {v: INF for v in graph}
  dist[source] = 0
  pq = MinHeap([(0, source)])
  while pq:
    d, u = pq.extractMin()
    if d > dist[u]: continue
    for v, w in graph[u]:
      if dist[u] + w < dist[v]:
        dist[v] = dist[u] + w
        pq.insert((dist[v], v))
  return dist

function fib(n):
  if n <= 1: return n
  dp = [0] * (n + 1)
  dp[1] = 1
  for i = 2 to n:
    dp[i] = dp[i-1] + dp[i-2]
  return dp[n]

