function knapsack(weights, values, W):
  n = len(weights)
  dp = 2D array [n+1][W+1] = 0
  for i = 1 to n:
    for w = 0 to W:
      if weights[i-1] <= w:
        dp[i][w] = max(
          dp[i-1][w],
          dp[i-1][w - weights[i-1]] + values[i-1]
        )
      else:
        dp[i][w] = dp[i-1][w]
  return dp[n][W]

