function topoSort(graph):
  inDegree = count incoming edges
  queue = [v for v if inDegree[v] == 0]
  result = []
  while queue:
    node = queue.dequeue()
    result.append(node)
    for neighbor in graph[node]:
      inDegree[neighbor]--
      if inDegree[neighbor] == 0:
        queue.enqueue(neighbor)
  return result

function find(x):
  if parent[x] != x:
    parent[x] = find(parent[x])  // path compression
  return parent[x]

function union(x, y):
