  parent[py] = px
  if rank[px] == rank[py]: rank[px]++

function insert(root, val):
  if root is null:
    return new Node(val)
  if val < root.val:
    root.left = insert(root.left, val)
  else:
    root.right = insert(root.right, val)
  return root

function heapSort(arr):
  n = len(arr)
  // Build max heap
  for i = n/2 - 1 downto 0:
    heapify(arr, n, i)
  // Extract elements
  for i = n - 1 downto 1:
    swap(arr[0], arr[i])
    heapify(arr, i, 0)

function heapify(arr, n, i):
  largest = i
  l = 2*i + 1, r = 2*i + 2
  if l < n and arr[l] > arr[largest]: largest = l
  if r < n and arr[r] > arr[largest]: largest = r
  if largest != i:
    swap(arr[i], arr[largest])
    heapify(arr, n, largest)

function aStar(start, goal, h):
  open = MinHeap([(h(start), start)])
  gScore = {start: 0}
  while open:
    _, current = open.extractMin()
    if current == goal: return reconstructPath()
    for neighbor, cost in edges(current):
      tentative = gScore[current] + cost
      if tentative < gScore.get(neighbor, INF):
        gScore[neighbor] = tentative
        f = tentative + h(neighbor)
        open.insert((f, neighbor))

