function countingSort(arr):
  maxVal = max(arr)
  count = [0] * (maxVal + 1)
  for x in arr:
    count[x]++
  output = []
  for i = 0 to maxVal:
    while count[i] > 0:
      output.append(i)
      count[i]--
  return output
